// ================================================
// n8n Code 节点专用代码
// 功能1：获取当前节点的输入数据（$input.all()）
// 功能2：动态提取当前输入 binary 中所有的图片
// 功能3：主动获取 Edit Fields 节点的 binary 图像数据（修正逻辑）
// 返回：合并后的数据，包含输入 JSON + 所有图片 + Edit Fields 的图片
// ================================================

const processInputAndImages = () => {
  try {
    // 1. 获取当前节点的输入数据（所有 items，通常是 1 个）
    const inputItems = $input.all();
    const firstInput = inputItems && inputItems.length > 0 ? inputItems[0] : {};
    const inputJson = firstInput.json || {};
    const inputBinary = firstInput.binary || {};

    // 2. 动态提取当前输入 binary 中所有的图片
    const allImages = {};
    let totalImageCount = 0;

    Object.keys(inputBinary).forEach(key => {
      // 不再限制特定前缀，直接提取所有 binary 图片
      if (inputBinary[key]) {
        allImages[key] = { ...inputBinary[key] };  // 深拷贝 binary 对象
        totalImageCount++;
      }
    });

    // 调试日志
    console.log('当前输入 binary 总键数:', Object.keys(inputBinary).length);
    console.log('提取到的图片数:', totalImageCount);
    console.log('图片键名列表:', Object.keys(allImages));

    // 3. 主动获取 Edit Fields 节点的 binary 图像数据（修正逻辑：寻找 cpimage 开头）
    let editFieldsImages = [];
    let editFieldsBinary = {};
    let editFieldsImageCount = 0;
    let editFieldsConnected = false;

    try {
      const editFieldsItems = $('Edit Fields').all();

      if (editFieldsItems && editFieldsItems.length > 0) {
        editFieldsItems.forEach((item, idx) => {
          const itemBinary = item.binary || {};

          Object.keys(itemBinary).forEach(key => {
            // 修正点：将 'ckimage' 改为 'cpimage'
            if (key.startsWith('ckimage') && itemBinary[key]) {
              const img = itemBinary[key];
              editFieldsImages.push({
                fieldName: key,
                fileName: img.fileName || '',
                mimeType: img.mimeType || '',
                fileExtension: img.fileExtension || '',
                fileSize: img.fileSize || '',
                sourceItemIndex: idx
              });

              // 带前缀避免冲突
              editFieldsBinary[`editFields_${key}_${idx}`] = itemBinary[key];
              editFieldsImageCount++;
            }
          });
        });

        if (editFieldsImageCount > 0) {
          editFieldsConnected = true;
          console.log(`成功从 Edit Fields 节点提取 ${editFieldsImageCount} 张图片`);
        }
      }
    } catch (editFieldsErr) {
      console.log('获取 Edit Fields 失败:', editFieldsErr.message);
    }

    // 4. 合并所有 binary：当前节点的所有图片 + Edit Fields 的 cpimage 图片
    const mergedBinary = {
      ...allImages,              // 所有图片
      ...editFieldsBinary       // editFields_cpimageX_...
    };

    // 5. 返回结果
    return [{
      json: {
        // 输入的原始 JSON 数据
        inputData: inputJson,

        // 当前节点的所有图片元数据
        allImages: allImages,
        totalImageCount: totalImageCount,
        imageKeys: Object.keys(allImages),

        // Edit Fields 的图片元数据（修正后）
        editFieldsImages: editFieldsImages,
        editFieldsImageCount: editFieldsImageCount,
        editFieldsConnected: editFieldsConnected,

        // 总计
        finalTotalImageCount: Object.keys(mergedBinary).length,
        source: 'merged_all_images_and_editFields'
      },

      // 合并后的 binary 数据
      binary: mergedBinary
    }];

  } catch (err) {
    console.log('执行失败:', err.message);
    return [{
      json: {
        error: '执行失败',
        errorDetail: err.message
      }
    }];
  }
};

// 执行并返回
return processInputAndImages();

