    console.log('Edit Fields binary 总键数:', Object.keys(editFieldsBinary).length);
    console.log('从 Edit Fields 提取到的图片数:', extractedImageCount);
    console.log('提取到的图片键名列表:', Object.keys(extractedImages));

    // 3. 返回结果
    return [{
      json: {
        // Edit Fields 节点的原始 JSON 数据
        editFieldsData: editFieldsData,

        // 提取出的图片元数据
        extractedImages: extractedImages,
        extractedImageCount: extractedImageCount,
        extractedImageKeys: Object.keys(extractedImages),

        // 源信息
        source: 'extracted_ckimage_cpimage_from_Edit_Fields'
      },

      // 包含所有从 Edit Fields 提取出的图片的 binary 数据
      binary: extractedImages
    }];

  } catch (err) {
    console.log('执行失败:', err.message);
    return [{
      json: {
        error: '执行失败',
        errorDetail: err.message
      }
    }];
  }
};

// 执行并返回
return processInputAndImages();

