const IMAGE_SOURCE_NODE = "Edit Fields"; // 图片来源节点名
const items = $input.all();
let resultItems = []; 

// 1. 获取并处理所有的 cpimage 图片，准备好“全额图片包”
let fullBinaryBundle = {};
try {
  const sourceItems = $(IMAGE_SOURCE_NODE).all();
  if (sourceItems.length > 0) {
    // 合并所有源数据的二进制（防止数据分散在不同 item）
    let combinedBinary = {};
    sourceItems.forEach(si => {
      if (si.binary) Object.assign(combinedBinary, si.binary);
    });

    // 筛选出 cpimage 开头的图片
    const cpimageKeys = Object.keys(combinedBinary)
      .filter(k => k.toLowerCase().startsWith('cpimage'))
      // 排序确保 1, 2, 3... 的逻辑顺序
      .sort((a, b) => a.localeCompare(b, undefined, {numeric: true, sensitivity: 'base'}));

    // 【重命名部分】将它们重命名为 1图, 2图... 并存入大礼包
    cpimageKeys.forEach((oldKey, index) => {
      const newKey = `${index + 1}图`;
      fullBinaryBundle[newKey] = combinedBinary[oldKey];
    });
  }
} catch (e) {
  console.error(`无法获取节点 ${IMAGE_SOURCE_NODE} 的数据: ${e.message}`);
}

// 2. 遍历输入，按文字描述拆分 Items
for (let item of items) {
  const rawText = item.json.output || item.json.prompt || "";
  if (!rawText) continue;

  const cleanText = rawText
    .replace(/<\|?begin_of_box\|?>/gi, '')
    .replace(/<\|?end_of_box\|?>/gi, '')
    .trim();

  const imagePattern = /第(\d+)[张幅]图片\s*([\s\S]*?)(?=第\d+[张幅]图片|$)/g;
  let match;

  while ((match = imagePattern.exec(cleanText)) !== null) {
    const num = match[1]; 
    const content = match[2].trim();

    // 3. 为每一段文字创建一个新 Item
    let newItem = {
      json: {
        prompt: content,      // 当前段落的描述
        image_index: num,     // 标记这是第几段描述
      },
      // 4. 【核心需求】把刚才准备好的所有图片全部复制进来
      // 这里使用的是深拷贝，确保每个 Item 都有独立的 1图, 2图...
      binary: { ...fullBinaryBundle } 
    };

    resultItems.push(newItem);
  }
}

// 5. 返回拆分后的结果
return resultItems;

// 同时提取 ckimage 和 cpimage 开头的 binary
