    json: {
      message: "缺少 ckimage 或 cpimage 前缀的图片，不提取 binary",
      hasCkimage: hasCkimage,
      hasCpimage: hasCpimage,
      extracted: false
    },
    binary: {}   // 不返回任何 binary
  }];
}

// 两个前缀都存在，开始提取并重命名
const extractedBinary = {};

let index = 1;

// 提取 ckimage 开头的
Object.keys(binary).forEach(key => {
  if (key.startsWith('ckimage')) {
    extractedBinary[`ckimage_${index}`] = { ...binary[key] };
    index++;
  }
});

// 提取 cpimage 开头的（继续编号）
Object.keys(binary).forEach(key => {
  if (key.startsWith('cpimage')) {
    extractedBinary[`cpimage_${index}`] = { ...binary[key] };
    index++;
  }
});

console.log(`成功提取 ckimage 和 cpimage 图片，共 ${index - 1} 张`);

return [{
  json: {
    message: "成功提取 ckimage 和 cpimage 的图片",
    ckimageCount: Object.keys(binary).filter(k => k.startsWith('ckimage')).length,
    cpimageCount: Object.keys(binary).filter(k => k.startsWith('cpimage')).length,
    extracted: true
  },
  binary: extractedBinary
}];

const items = $input.all();
const outputs = [];

for (let i = 0; i < items.length; i++) {
  const bin = items[i].binary || {};
  const keys = Object.keys(bin);

  if (!keys.length) {
    outputs.push({ json: { key: '', fileName: '', mimeType: '', url: '' } });
    continue;
  }

  for (const key of keys) {
    const meta = bin[key] || {};
    let url = '';
    try {
      const buf = await this.helpers.getBinaryDataBuffer(i, key);
      const mime = meta.mimeType || meta.mimetype || 'application/octet-stream';
      const base64 = Buffer.isBuffer(buf) ? buf.toString('base64') : Buffer.from(buf).toString('base64');
      url = base64 ? `data:${mime};base64,${base64}` : '';
    } catch (_) {
      const mime = meta.mimeType || meta.mimetype || 'application/octet-stream';
      const data = meta.data;
      if (typeof data === 'string' && data.length) url = `data:${mime};base64,${data}`;
    }

    outputs.push({
      json: {
        key,
        fileName: meta.fileName || meta.filename || key,
        mimeType: meta.mimeType || meta.mimetype || '',
        url
      }
    });
  }
}

return outputs.length ? outputs : [{ json: { key: '', fileName: '', mimeType: '', url: '' } }];

